package org.apache.commons.math.optimization.fitting;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.math.optimization.fitting.steps",
    plugin = {"pretty", "html:target/cucumber-reports"}
)
public class CucumberTest {
}

package org.apache.commons.math.optimization.fitting.steps;

import org.apache.commons.math.FunctionEvaluationException;
import org.apache.commons.math.analysis.function.Gaussian;
import org.apache.commons.math.optimization.OptimizationException;
import org.apache.commons.math.optimization.fitting.CurveFitter;
import org.apache.commons.math.optimization.fitting.GaussianFitter;
import org.apache.commons.math.optimization.general.LevenbergMarquardtOptimizer;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.junit.Assert;

import java.util.ArrayList;
import java.util.List;

public class StepDefs {

    private GaussianFitter fitter;
    private double[] parameters;
    private Exception exception;

    @Given("a GaussianFitter initialized with a LevenbergMarquardtOptimizer")
    public void a_gaussian_fitter_initialized_with_a_levenberg_marquardt_optimizer() {
        fitter = new GaussianFitter(new LevenbergMarquardtOptimizer());
    }

    @Given("the following observed data points:")
    public void the_following_observed_data_points(List<List<Double>> dataPoints) {
        for (List<Double> point : dataPoints) {
            double x = point.get(0);
            double y = point.get(1);
            fitter.addObservedPoint(1.0, x, y);
        }
    }

    @When("I fit the model to the data")
    public void i_fit_the_model_to_the_data() {
        try {
            parameters = fitter.fit();
            exception = null;
        } catch (Exception e) {
            exception = e;
        }
    }

    @Then("the fitting process should complete without throwing exceptions")
    public void the_fitting_process_should_complete_without_throwing_exceptions() {
        Assert.assertNull("Fitting process threw exception: " + (exception != null ? exception.getMessage() : "null"), exception);
    }

    @Then("the estimated mean parameter should be approximately {double}")
    public void the_estimated_mean_parameter_should_be_approximately(double expectedMean) {
        Assert.assertNotNull("Fitting failed, no parameters available", parameters);
        Assert.assertEquals("Estimated mean parameter", expectedMean, parameters[1], 1e-6);
    }

    @Then("the estimated sigma parameter should be approximately {double}")
    public void the_estimated_sigma_parameter_should_be_approximately(double expectedSigma) {
        Assert.assertNotNull("Fitting failed, no parameters available", parameters);
        Assert.assertEquals("Estimated sigma parameter", expectedSigma, parameters[2], 1e-6);
    }
}

